#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define ull unsigned long long
#define inf 0x3f3f3f3f
#define NoAns puts("-1")
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
CI MAXN = 1e6 + 5;
string s;
int n, a[MAXN], vis[MAXN << 1], ans = 0;
int main(void)
{
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	memset(vis, 0x3f, sizeof vis);
	cin >> s;
	for (int i = 0; i < s.size(); ++i)
	{
		if (s[i] == 'G')a[i + 1] = a[i] + 1;
		else a[i + 1] = a[i] - 1;
	}
	vis[s.size() + 1] = 0;
	for (int i = 1; i <= s.size(); ++i)
	{
		if (vis[a[i] + s.size() + 1] != inf) ans = max(ans, i - vis[a[i] + s.size() + 1]);
		else vis[a[i] + s.size() + 1] = i;
	}
	cout << ans;
	return false;
}
